    answer: "Currying — ko'p argumentli funksiyani birma-bir argument qabul qiluvchi funksiyalar zanjiriga aylantirish: f(a, b, c) → f(a)(b)(c). ''javascript // Oddiy funksiya function add(a, b, c) { return a + b + c; } add(1, 2, 3); // 6 // Qo'lda curried versiya function curriedAdd(a) { return function(b) { return function(c) { return a + b + c; }; }; } curriedAdd(1)(2)(3); // 6 ' Universal curry implementation: 'javascript function curry(fn) { return function curried(...args) { // Argumentlar yetarli bo'lsa — asl funksiyani chaqir if (args.length >= fn.length) { return fn.apply(this, args); } // Yetmasa — yangi funksiya qaytar, oldingi args ni eslab qol (closure) return function(...moreArgs) { return curried.apply(this, [...args, ...moreArgs]); }; }; } // Ishlatish const add = curry((a, b, c) => a + b + c); add(1)(2)(3); // 6 add(1, 2)(3); // 6 add(1)(2, 3); // 6 add(1, 2, 3); // 6 — oddiy chaqiruv ham ishlaydi // Amaliy misol const multiply = curry((a, b) => a * b); const double = multiply(2); // partial application const triple = multiply(3); double(5); // 10 triple(5); // 15 ''",
