    answer: "Function Composition — bir necha kichik funksiyalarni birlashtirish orqali yangi funksiya hosil qilish. compose(f, g)(x) = f(g(x)). ''javascript // Oddiy misol — qo'lda composition const trim = str => str.trim(); const toLower = str => str.toLowerCase(); const split = str => str.split(\" \"); // Qo'lda const result = split(toLower(trim(\" SALOM DUNYO \"))); // [\"salom\", \"dunyo\"] // compose — O'NGDAN CHAPGA (matematikadagi kabi) function compose(...fns) { return function(value) { return fns.reduceRight((acc, fn) => fn(acc), value); }; } const processText = compose(split, toLower, trim); processText(\" SALOM DUNYO \"); // [\"salom\", \"dunyo\"] // Bajarilish: trim → toLower → split (o'ngdan chapga o'qiladi) // pipe — CHAPDAN O'NGGA (o'qishga qulay) function pipe(...fns) { return function(value) { return fns.reduce((acc, fn) => fn(acc), value); }; } const processText2 = pipe(trim, toLower, split); processText2(\" SALOM DUNYO \"); // [\"salom\", \"dunyo\"] // Bajarilish: trim → toLower → split (chapdan o'ngga, tabiiy tartib) ''",
