    answer: "Express.js pattern — har bir middleware (ctx, next). next() chaqirilmasa zanjir to'xtaydi: ''javascript class Pipeline { constructor() { this.stack = []; } use(fn) { this.stack.push(fn); return this; } async execute(ctx) { let i = 0; const stack = this.stack; async function next() { if (i >= stack.length) return; const fn = stack[i++]; await fn(ctx, next); } await next(); return ctx; } } // Test const app = new Pipeline(); app.use(async (ctx, next) => { console.log(\"→ Logger\"); await next(); console.log(\"← Logger\"); }); app.use(async (ctx, next) => { if (!ctx.token) { ctx.error = \"401 Unauthorized\"; return; // next() chaqirilmaydi — zanjir to'xtaydi } ctx.user = { name: \"Ali\" }; await next(); }); app.use(async (ctx, next) => { ctx.body = { data: \"OK\", user: ctx.user }; await next(); }); // Auth bor await app.execute({ token: \"abc\" }); // → Logger → auth pass → handler → ← Logger // Auth yo'q const result = await app.execute({}); // → Logger → auth fail (ctx.error = \"401\") → ← Logger ' Asosiy nuqtalar: - next() — closure orqali i index'ni ushlab turadi - Har bir middleware next() chaqirmasa — qolgan middleware'lar bajarilmaydi - Onion model — birinchi middleware oxirida ham kod baja",
