    answer: "Command — har bir amalni object sifatida encapsulate qiladi (execute() va undo() metodlari bilan). Bu undo/redo, command history va queue qilishni osonlashtiradi. ''javascript // Har bir command — execute() va undo() class SetValueCommand { constructor(obj, key, newValue) { this.obj = obj; this.key = key; this.newValue = newValue; this.oldValue = obj[key]; // undo uchun } execute() { this.obj[this.key] = this.newValue; } undo() { this.obj[this.key] = this.oldValue; } } // History manager class CommandHistory { #undoStack = []; #redoStack = []; execute(cmd) { cmd.execute(); this.#undoStack.push(cmd); this.#redoStack = []; // yangi amal — redo tozalanadi } undo() { const cmd = this.#undoStack.pop(); if (cmd) { cmd.undo(); this.#redoStack.push(cmd); } } redo() { const cmd = this.#redoStack.pop(); if (cmd) { cmd.execute(); this.#undoStack.push(cmd); } } } const data = { name: \"Ali\", age: 25 }; const history = new CommandHistory(); history.execute(new SetValueCommand(data, \"name\", \"Vali\")); console.log(data.name); // \"Vali\" history.undo(); console.log(data.name); // \"Ali\" history.redo(); console.log(data.name); // \"Vali\" '' Real-world: VS Code undo/redo, Git commit'lar, Redux action'lar",
